sql:
SELECT MAX(version) AS latest_version
FROM components
WHERE component_id = (SELECT MAX(component_id) FROM components);

external_knowledge:
- BOM stands for Bill of Materials, a list of the raw materials, subassemblies, intermediate assemblies, sub-components, components, parts, and the quantities of each needed to manufacture an end product; 
- POS stands for Point of Sale, the time and place at which a retail transaction is completed; 
- FIFO stands for First-In-First-Out, an inventory valuation method assuming the first items purchased are the first items sold; 
- 'Net 30' is a payment term meaning the full amount is due within 30 days of the invoice date.

sql:
SELECT 
  (SELECT SUM(stock) FROM inventory WHERE warehouse_id = 1) AS total_stock_warehouse_1,
  (SELECT component_id FROM inventory ORDER BY stock ASC LIMIT 1) AS lowest_stock_component;

SELECT SUM(cost) AS total_cost
FROM sourcing
WHERE supplier_id = 1;
